 if(argc<3||argc>4)throw Err("usage: checkpoint n mask [chunk_divisors]"); int n=std::stoi(argv[1]);u64 mask=std::stoull(argv[2]);u64 chunk=argc==4?std::stoull(argv[3]):0;
