 const char* state_env=std::getenv("NOVA_MITM_STATE_DIR");std::string state_dir=state_env?state_env:"/tmp";if(!state_dir.empty()&&state_dir.back()!='/')state_dir+='/';std::string base=state_dir+"nova_mitm_safe_n"+std::to_string(n)+"_mask"+std::to_string(mask),cache=base+".bin",ckpt=base+".ckpt";std::vector<u128>A,B;
 {std::ifstream in(cache,std::ios::binary);if(in){CacheHeader h{};in.read((char*)&h,sizeof(h));if(!in||h.magic!=0x534146454d49544dULL||h.n!=(u64)n||h.mask!=mask||h.total!=total)throw Err("bad cache header");A.resize(h.asz);B.resize(h.bsz);in.read((char*)A.data(),A.size()*sizeof(u128));in.read((char*)B.data(),B.size()*sizeof(u128));if(!in)throw Err("short cache");std::cerr<<"cache=loaded\n";}else{A.reserve(besta);B.reserve(bestb);gen(fa,0,1,Y,A);gen(fb,0,1,Y,B);std::sort(A.begin(),A.end());std::sort(B.begin(),B.end());if(A.size()>B.size())std::swap(A,B);CacheHeader h{0x534146454d49544dULL,(u64)n,mask,(u64)A.size(),(u64)B.size(),total};std::ofstream out(cache,std::ios::binary);out.write((char*)&h,sizeof(h));out.write((char*)A.data(),A.size()*sizeof(u128));out.write((char*)B.data(),B.size()*sizeof(u128));if(!out)throw Err("cache write");std::cerr<<"cache=created\n";}}
 if(A.empty()||B.empty())throw Err("empty truncated half");if(!std::is_sorted(A.begin(),A.end())||!std::is_sorted(B.begin(),B.end()))throw Err("unsorted cache");if(std::adjacent_find(A.begin(),A.end())!=A.end()||std::adjacent_find(B.begin(),B.end())!=B.end())throw Err("duplicate half");std::cerr<<"split="<<A.size()<<"x"<<B.size()<<" total="<<total<<"\n";
