 u128 scale=u128(1)<<(t-1),D=(E+W+1)/scale,bound=Y/scale;auto resolve=[&](bool blocked,u128 left,u64 K,u128 right,u128 gap){u128 umax=left;E+=scale*umax;cprod*=cpp_int(K)+1;std::string row="layer="+std::to_string(t)+",scale="+dec(scale)+",core_bound="+dec(bound)+",gap_threshold="+dec(D)+",connected_max_core="+dec(umax)+",connected_count="+std::to_string(K)+",carrier_endpoint="+dec(E);if(blocked)row+=",first_blocking_left="+dec(left)+",first_blocking_right="+dec(right)+",first_blocking_gap="+dec(gap);else row+=",first_blocking_gap=NONE";rows.push_back(row);};
